use std::collections::HashMap;

#[derive(Eq, Hash, PartialEq)]
struct ContextIdZeroSize;

impl std::fmt::Display for ContextIdZeroSize {
    fn fmt(&self, f: &mut std::fmt::Formatter) -> std::fmt::Result {
        write!(f, "<ContextID>")
    }
}

struct JobExecutionTracker {
    context_map: HashMap<ContextIdZeroSize, u32>,
}

impl JobExecutionTracker {
    fn new() -> Self {
        JobExecutionTracker { 
            context_map: HashMap::new()
        }
    }

    fn register_job(&mut self, id: ContextIdZeroSize, job_code_hash: u32) -> Result<(), String> {
        if self.context_map.contains_key(&id) {
            return Err("Context ID already registered".to_string());
        }
        self.context_map.insert(id, job_code_hash);
        Ok(())
    }

    fn get_status(&self, id: &ContextIdZeroSize) -> Option<u32> {
        self.context_map.get(id).copied()
    }
}

