fn generate_source_map<T>(input_data: Vec<(String, T)>) -> HashMap<String, String> where T: std::fmt::Debug {
    let mut map = HashMap::new();
    for (key, value) in input_data { 
        println!("Processing key: {}", key);
        match stringify!(T) {
            "i32" => { 
                map.insert(format!("{}", key), format!("Source for integer value."));
            },
            _ => { 
                map.insert(format!("{}", key), format!("Unknown source marker for type {:?}.", value));
            }
        }
    }
    map
}

fn main() {
    let data: Vec<(String, i32)> = vec![ 
        ("main_entry".to_string(), 10),
        ("helper_call".to_string(), 5)
    ];

    let source_map = generate_source_map(data);

    for (key, location) in &source_map {
        println!("Found mapping for \"{}\": \"{}\"", key, location);
    }
}
